"use strict";(globalThis.webpackChunksap_architecture_center=globalThis.webpackChunksap_architecture_center||[]).push([[19171],{67081(e){e.exports=JSON.parse('{"tag":{"label":"AI-native North Star architecture","permalink":"/architecture-center-quick-start/docs/tags/ai-native-north-star","description":"The AI-native North Star architecture defines the target state of SAP\'s technology landscape. It is not a specification, roadmap, or promise of delivery. It is a direction of travel; a statement of how AI, data, processes, and the platform must work together as intelligence becomes the norm rather than an add-on.","allTagsPath":"/architecture-center-quick-start/docs/tags","count":20,"items":[{"id":"north-star-arch/ai-native-northstar-arch/acknowledgement/id-nsa-13","title":"Acknowledgement","description":"Acknowledgement of the core contributors who shaped the AI-native North Star architecture.","permalink":"/architecture-center-quick-start/docs/ai-native-north-star-architecture/acknowledgement"},{"id":"north-star-arch/ai-native-northstar-arch/ai-native-nsa-vision/id-nsa-2","title":"AI-native North Star architecture - Vision","description":"SAP\'s AI-native North Star architecture vision: four reimagined layers \u2014 User Experience, Process, Foundation, and Platform \u2014 work together as a system of context where Joule, agents, the SAP Knowledge Graph, and enterprise data compound into measurable business outcomes.","permalink":"/architecture-center-quick-start/docs/ai-native-north-star-architecture/vision"},{"id":"north-star-arch/ai-native-northstar-arch/foreword/id-nsa-foreword-2","title":"Anirban Majumdar","description":"The AI-native North Star architecture is SAP\'s blueprint for the Autonomous Enterprise, where agents, orchestration, and data operate in a continuous closed loop to transform intent into trusted business outcomes at scale.","permalink":"/architecture-center-quick-start/docs/ai-native-north-star-architecture/foreword/anirban-majumdar"},{"id":"north-star-arch/ai-native-northstar-arch/architecting-for-the-quantum-era/id-nsa-11","title":"Architecting for the Quantum Era","description":"SAP\'s AI-native North Star architecture prepares for the quantum era through three principles: quantum co-processors handle specialized optimization and simulation workloads, cloud-native APIs abstract vendor differences, and scoped analytical use keeps transactional systems deterministic \u2014 enabling incremental quantum adoption without rearchitecting.","permalink":"/architecture-center-quick-start/docs/ai-native-north-star-architecture/architecting-for-the-quantum-era"},{"id":"north-star-arch/ai-native-northstar-arch/closing-note/id-nsa-12","title":"Closing Note","description":"The AI-native enterprise is a cybernetic system where software, data, and people evolve together through continuous feedback. For architects, the role shifts to agentic engineering \u2014 orchestrating agents through context, harness, and specification engineering \u2014 grounded in SAP\'s structural advantages of deep integration, process expertise, and enterprise trust.","permalink":"/architecture-center-quick-start/docs/ai-native-north-star-architecture/closing-note"},{"id":"north-star-arch/ai-native-northstar-arch/customer-specific-development-services/id-nsa-10","title":"Customer-Specific Development Services","description":"SAP Development Services is the AI-native offering for customer-specific extensions that continuously learn and adapt in production. Using agentic engineering and accelerator-driven synthesis, it unifies discovery, design, build, and hardening into a continuous agent-orchestrated flow \u2014 delivering upgrade-safe solutions that compound value from day one.","permalink":"/architecture-center-quick-start/docs/ai-native-north-star-architecture/customer-specific-development-services"},{"id":"north-star-arch/ai-native-northstar-arch/ecosystem/id-nsa-8","title":"Ecosystem - The Marketplace for Agents, Tools, and Extensions","description":"The SAP AI Agent Hub is the enterprise marketplace for discovering, publishing, and composing agents, tools, and extensions. Built on Open Resource Discovery, SAP Business Data Cloud, and the SAP Knowledge Graph, it enables partners and customers to co-create domain-specific agents within a shared governance and trust framework.","permalink":"/architecture-center-quick-start/docs/ai-native-north-star-architecture/ecosystem"},{"id":"north-star-arch/ai-native-northstar-arch/executive-summary/id-nsa-1","title":"Executive Summary","description":"Enterprise AI shifts from AI-first to AI-native: SAP\'s architecture unlocks five decades of business context to build a system of context where agents reason across the full landscape, processes learn from every interaction, and software evolves from SaaS to Outcome as a Service.","permalink":"/architecture-center-quick-start/docs/ai-native-north-star-architecture/executive-summary"},{"id":"north-star-arch/ai-native-northstar-arch/foundation-layer/id-nsa-5","title":"Foundation Layer","description":"The AI-native Foundation Layer unites Data and AI as the intelligent core of enterprise processes. SAP Business Data Cloud and the SAP Knowledge Graph provide semantic grounding and governed data, while orchestration, model services, context engineering, and continuous improvement compound enterprise knowledge with every interaction.","permalink":"/architecture-center-quick-start/docs/ai-native-north-star-architecture/foundation-layer"},{"id":"north-star-arch/ai-native-northstar-arch/foreword/id-nsa-foreword-5","title":"Geoff Scott","description":"ASUG\'s perspective on SAP\'s AI-native North Star architecture: customers need clarity from the platforms they have built their businesses on, and ASUG commends SAP for the rigor and transparency that went into pulling it together for the community.","permalink":"/architecture-center-quick-start/docs/ai-native-north-star-architecture/foreword/geoff-scott"},{"id":"north-star-arch/ai-native-northstar-arch/integration-security-ethics-governance/id-nsa-7","title":"Integration, Security, Ethics & Governance","description":"Cross-cutting governance for SAP\'s AI-native architecture: a single governed gateway enforces integration boundaries, agents operate as first-class principals with scoped identity, a Three-Tier AI Defense Architecture addresses agentic threats, and structured AI ethics review ensures responsible deployment under the EU AI Act and global compliance frameworks.","permalink":"/architecture-center-quick-start/docs/ai-native-north-star-architecture/integration-security-ethics-governance"},{"id":"north-star-arch/ai-native-northstar-arch/key-terms/id-nsa-14","title":"Key Terms","description":"Key terms and definitions used in the SAP AI-native North Star architecture document.","permalink":"/architecture-center-quick-start/docs/north-star-arch/ai-native-northstar-arch/key-terms/"},{"id":"north-star-arch/ai-native-northstar-arch/foreword/id-nsa-foreword-1","title":"Philipp Herzig","description":"Enterprise AI shifts from AI-first to AI-native: SAP\'s architecture unlocks five decades of business context to build a system of context where agents reason across the full landscape, processes learn from every interaction, and software evolves from SaaS to Outcome as a Service.","permalink":"/architecture-center-quick-start/docs/ai-native-north-star-architecture/foreword/philipp-herzig"},{"id":"north-star-arch/ai-native-northstar-arch/platform-layer/id-nsa-6","title":"Platform Layer","description":"The AI-native Platform Layer is where applications, agents, and workflows run at enterprise scale. SAP BTP provides a managed agent runtime with built-in security, observability, tenant isolation, and governance \u2014 turning stateless AI models into reliable enterprise agents with sovereign AI as an architectural constraint.","permalink":"/architecture-center-quick-start/docs/ai-native-north-star-architecture/platform-layer"},{"id":"north-star-arch/ai-native-northstar-arch/process-layer/id-nsa-4","title":"Process Layer","description":"The AI-native Process Layer shifts business logic from rigid application-bound workflows to agent-driven orchestration. Applications become capability providers, agents reason across domains using a reason-act-observe loop, and Joule Studio unifies the design-time for building agentic solutions from intent to production.","permalink":"/architecture-center-quick-start/docs/ai-native-north-star-architecture/process-layer"},{"id":"north-star-arch/ai-native-northstar-arch/id-nsa-0","title":"SAP AI-native North Star architecture","description":"The AI Native North Star Architecture defines the target state of SAP\'s technology landscape. It is not a specification, roadmap, or promise of delivery. It is a direction of travel; a statement of how AI, data, processes, and the platform must work together as intelligence becomes the norm rather than an add-on.","permalink":"/architecture-center-quick-start/docs/ai-native-north-star-architecture"},{"id":"north-star-arch/ai-native-northstar-arch/foreword/id-nsa-foreword-3","title":"Stefan Nogly","description":"DSAG\'s perspective on SAP\'s AI-native North Star architecture: a strategic roadmap for AI-native enterprise transformation, with shared responsibility for SAP, DSAG, and user companies to continue the dialogue and develop viable solutions together.","permalink":"/architecture-center-quick-start/docs/ai-native-north-star-architecture/foreword/stefan-nogly"},{"id":"north-star-arch/ai-native-northstar-arch/resilient-and-sovereign-cloud/id-nsa-9","title":"The Resilient and Sovereign Cloud","description":"SAP\'s resilient and sovereign cloud strategy delivers AI-native workloads across public, private, sovereign, and on-site deployment models. Operational excellence is ensured through high availability, elasticity, AI-enabled operations, OpenTelemetry observability, and sustainable infrastructure \u2014 all governed to meet local compliance and data sovereignty requirements.","permalink":"/architecture-center-quick-start/docs/ai-native-north-star-architecture/resilient-and-sovereign-cloud"},{"id":"north-star-arch/ai-native-northstar-arch/foreword/id-nsa-foreword-4","title":"Thomas Henzler","description":"DSAG\'s perspective on governance as a key to success in AI transformation: the AI-native North Star architecture provides a strategic framework for AI transformation at the various levels operationalized within companies.","permalink":"/architecture-center-quick-start/docs/ai-native-north-star-architecture/foreword/thomas-henzler"},{"id":"north-star-arch/ai-native-northstar-arch/user-experience-layer/id-nsa-3","title":"User Experience Layer","description":"The AI-native User Experience Layer reimagines how users interact with enterprise software: from navigating apps to stating intent. Joule Work unifies generative, voice, and multimodal experiences across five modes \u2014 Discover, Conversations, Spaces, Jobs, and Develop \u2014 assembled dynamically around each user\'s context and goals.","permalink":"/architecture-center-quick-start/docs/ai-native-north-star-architecture/user-experience-layer"}],"unlisted":false}}')}}]);